VALUES
  ('heelevel3-e3452428-moex-00056', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '關於人民依法申請閱覽卷宗之敘述，下列何者錯誤？', '["涉及國防、軍事、外交機密且依法規規定有保密必要之卷宗資料，不予提供", "人民申請檢視公文資料，行政機關應視具體個案，分別適用行政程序法、檔案法或政府資訊公 開法之相關規定", "涉及一般公務機密之行政決定前擬稿或準備文件，與公益無關之部分，依法仍應准許閱覽", "當事人於閱覽資料或卷宗時發現有錯誤，得檢具事實證明依法申請相關機關更正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00057', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '甲、乙、丙、丁、戊、己等6人共同提起訴願，依訴願法規定，下列敘述何者錯誤？', '["甲等6人因同一原因事實，受課稅處分，得共同提起訴願", "甲、乙為訴願選定代表人，則甲、乙均得單獨代表共同訴願人為訴願行為", "甲等6人經通知逾期未選定訴願代表人，受理訴願機關得依職權指定訴願代表人", "甲等6人共同提起訴願，得選定甲、乙、丙、丁為代表人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00058', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '國家成立鹽業公司，販賣國民海洋深層水。下列敘述何者正確？', '["該公司不得主張契約自由", "若其產品發生食安事件，不得請求國家賠償", "國家得以公法法規管制該交易", "該交易應受行政法原則之約束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00059', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '依司法院大法官解釋或憲法法庭裁判意旨，下列何者之救濟應提起課予義務訴訟？', '["教師因違反教師法遭聘任學校決定自次一學年起不予續聘", "本國人就其外國籍配偶依法申請入境遭駁回處分", "教師因體罰學生遭決議解聘且4年內不得擔任教師，經主管機關核准", "人民依法請求就國有林地中濫墾地訂立租地契約遭拒絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00060', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '甲為中華民國國籍人士，其與A國籍乙在A國辦理結婚登記。嗣後乙持A國結婚證書向我國駐 A國代表處申請驗證結婚證書及核發依親居留簽證。然而我國駐A國代表處卻認為，甲與乙在面 談時對於結婚重要事實陳述不一致，因此駁回乙之簽證申請。依司法實務之見解，下列敘述何者 正確？', '["甲得以自己名義提起課予義務訴訟，請求發給乙簽證", "乙不具有我國國籍，因此無法提起行政救濟", "甲得以自己名義，提起撤銷訴願及撤銷訴訟，以資救濟", "因為甲本身並非依法得申請簽證之當事人，因此無法提起行政救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00061', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00062', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-114-3082b5f1', 'sub-heelevel3-e3452428-04', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:44+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "201", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般民政"}'::jsonb, NULL),
  ('heelevel3-e3452428-moex-00063', 'heelevel3-e3452428', 'heelevel3-e3452428-moex-113-c4ffbd92', 'sub-heelevel3-e3452428-05', NULL, 'essay', '民國 88 年出爐的「地方制度法」確立我國現行地方自治制度。請說明
